import numpy as np

def select_next_node(current_node, truck_nodes, destination_node, unvisited_nodes, distance_matrix):
    next_node = None
    min_time = np.inf

    for node in unvisited_nodes:
        travel_time = distance_matrix[current_node, node]

        for truck_node in truck_nodes:
            time_to_truck = distance_matrix[truck_node, node]
            total_time = max(travel_time, time_to_truck)

            if total_time < min_time:
                min_time = total_time
                next_node = node

    return next_node
